import{_ as e,o as a,c as s,ae as r}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"REST API Reference","description":"","frontmatter":{},"headers":[],"relativePath":"api.md","filePath":"api.md"}'),o={name:"api.md"};function i(d,t,n,p,h,l){return a(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="rest-api-reference" tabindex="-1">REST API Reference <a class="header-anchor" href="#rest-api-reference" aria-label="Permalink to &quot;REST API Reference&quot;">​</a></h1><p>All endpoints require authentication via:</p><ul><li><code>Authorization: Bearer &lt;jwt&gt;</code> header, OR</li><li><code>X-API-Key: &lt;key&gt;</code> header</li></ul><p>Base URL: <code>http://localhost:8000</code> (or your server URL)</p><h2 id="auth" tabindex="-1">Auth <a class="header-anchor" href="#auth" aria-label="Permalink to &quot;Auth&quot;">​</a></h2><h3 id="post-api-auth-register" tabindex="-1">POST /api/auth/register <a class="header-anchor" href="#post-api-auth-register" aria-label="Permalink to &quot;POST /api/auth/register&quot;">​</a></h3><p>Create a new user account.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>email</td><td>string</td><td>Yes</td><td>User email address</td></tr><tr><td>password</td><td>string</td><td>Yes</td><td>User password</td></tr><tr><td>name</td><td>string</td><td></td><td>Display name</td></tr></tbody></table><p><strong>Response:</strong> User object with JWT token</p><h3 id="post-api-auth-login" tabindex="-1">POST /api/auth/login <a class="header-anchor" href="#post-api-auth-login" aria-label="Permalink to &quot;POST /api/auth/login&quot;">​</a></h3><p>Authenticate and receive a JWT token.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>email</td><td>string</td><td>Yes</td><td>User email address</td></tr><tr><td>password</td><td>string</td><td>Yes</td><td>User password</td></tr></tbody></table><p><strong>Response:</strong> <code>{ &quot;access_token&quot;: &quot;...&quot;, &quot;token_type&quot;: &quot;bearer&quot; }</code></p><h3 id="get-api-auth-me" tabindex="-1">GET /api/auth/me <a class="header-anchor" href="#get-api-auth-me" aria-label="Permalink to &quot;GET /api/auth/me&quot;">​</a></h3><p>Return the currently authenticated user.</p><p><strong>Response:</strong> User object</p><h2 id="sifts" tabindex="-1">Sifts <a class="header-anchor" href="#sifts" aria-label="Permalink to &quot;Sifts&quot;">​</a></h2><h3 id="get-api-sifts" tabindex="-1">GET /api/sifts <a class="header-anchor" href="#get-api-sifts" aria-label="Permalink to &quot;GET /api/sifts&quot;">​</a></h3><p>List all sifts for the authenticated user.</p><p><strong>Response:</strong> Array of sift objects</p><h3 id="post-api-sifts" tabindex="-1">POST /api/sifts <a class="header-anchor" href="#post-api-sifts" aria-label="Permalink to &quot;POST /api/sifts&quot;">​</a></h3><p>Create a new sift.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>name</td><td>string</td><td>Yes</td><td>Sift name</td></tr><tr><td>instructions</td><td>string</td><td>Yes</td><td>What to extract (plain English)</td></tr><tr><td>description</td><td>string</td><td></td><td>Optional description</td></tr></tbody></table><p><strong>Response:</strong> Sift object</p><h3 id="get-api-sifts-id" tabindex="-1">GET /api/sifts/:id <a class="header-anchor" href="#get-api-sifts-id" aria-label="Permalink to &quot;GET /api/sifts/:id&quot;">​</a></h3><p>Get a sift by ID.</p><p><strong>Response:</strong> Sift object</p><h3 id="patch-api-sifts-id" tabindex="-1">PATCH /api/sifts/:id <a class="header-anchor" href="#patch-api-sifts-id" aria-label="Permalink to &quot;PATCH /api/sifts/:id&quot;">​</a></h3><p>Update a sift&#39;s name, instructions, or description.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>name</td><td>string</td><td></td><td>New sift name</td></tr><tr><td>instructions</td><td>string</td><td></td><td>New extraction instructions</td></tr><tr><td>description</td><td>string</td><td></td><td>New description</td></tr></tbody></table><p><strong>Response:</strong> Updated sift object</p><h3 id="delete-api-sifts-id" tabindex="-1">DELETE /api/sifts/:id <a class="header-anchor" href="#delete-api-sifts-id" aria-label="Permalink to &quot;DELETE /api/sifts/:id&quot;">​</a></h3><p>Delete a sift and all its records.</p><p><strong>Response:</strong> <code>204 No Content</code></p><h3 id="post-api-sifts-id-upload" tabindex="-1">POST /api/sifts/:id/upload <a class="header-anchor" href="#post-api-sifts-id-upload" aria-label="Permalink to &quot;POST /api/sifts/:id/upload&quot;">​</a></h3><p>Upload one or more documents to a sift for processing.</p><p><strong>Request:</strong> <code>multipart/form-data</code> with one or more <code>files</code> fields.</p><p><strong>Response:</strong> Array of created document objects</p><h3 id="post-api-sifts-id-reindex" tabindex="-1">POST /api/sifts/:id/reindex <a class="header-anchor" href="#post-api-sifts-id-reindex" aria-label="Permalink to &quot;POST /api/sifts/:id/reindex&quot;">​</a></h3><p>Reprocess all documents in the sift from scratch.</p><p><strong>Response:</strong> <code>202 Accepted</code></p><h3 id="post-api-sifts-id-reset" tabindex="-1">POST /api/sifts/:id/reset <a class="header-anchor" href="#post-api-sifts-id-reset" aria-label="Permalink to &quot;POST /api/sifts/:id/reset&quot;">​</a></h3><p>Clear all extracted records from the sift (keeps documents).</p><p><strong>Response:</strong> <code>204 No Content</code></p><h3 id="get-api-sifts-id-records" tabindex="-1">GET /api/sifts/:id/records <a class="header-anchor" href="#get-api-sifts-id-records" aria-label="Permalink to &quot;GET /api/sifts/:id/records&quot;">​</a></h3><p>Get all extracted records for a sift.</p><p><strong>Query parameters:</strong></p><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>limit</td><td>integer</td><td>Max records to return (default: 100)</td></tr><tr><td>skip</td><td>integer</td><td>Records to skip for pagination</td></tr></tbody></table><p><strong>Response:</strong> Array of record objects</p><h3 id="get-api-sifts-id-records-csv" tabindex="-1">GET /api/sifts/:id/records/csv <a class="header-anchor" href="#get-api-sifts-id-records-csv" aria-label="Permalink to &quot;GET /api/sifts/:id/records/csv&quot;">​</a></h3><p>Export all records as a CSV file download.</p><p><strong>Response:</strong> <code>text/csv</code> file attachment</p><h3 id="post-api-sifts-id-query" tabindex="-1">POST /api/sifts/:id/query <a class="header-anchor" href="#post-api-sifts-id-query" aria-label="Permalink to &quot;POST /api/sifts/:id/query&quot;">​</a></h3><p>Run a natural language query against the sift&#39;s records.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>query</td><td>string</td><td>Yes</td><td>Natural language query (e.g. &quot;Total by client&quot;)</td></tr></tbody></table><p><strong>Response:</strong> Query results as structured data</p><h3 id="post-api-sifts-id-chat" tabindex="-1">POST /api/sifts/:id/chat <a class="header-anchor" href="#post-api-sifts-id-chat" aria-label="Permalink to &quot;POST /api/sifts/:id/chat&quot;">​</a></h3><p>Chat with the sift&#39;s data in natural language.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>message</td><td>string</td><td>Yes</td><td>User message</td></tr><tr><td>history</td><td>array</td><td></td><td>Previous messages for context</td></tr></tbody></table><p><strong>Response:</strong> AI-generated conversational response</p><h2 id="folders" tabindex="-1">Folders <a class="header-anchor" href="#folders" aria-label="Permalink to &quot;Folders&quot;">​</a></h2><h3 id="get-api-folders" tabindex="-1">GET /api/folders <a class="header-anchor" href="#get-api-folders" aria-label="Permalink to &quot;GET /api/folders&quot;">​</a></h3><p>List all folders for the authenticated user.</p><p><strong>Response:</strong> Array of folder objects</p><h3 id="post-api-folders" tabindex="-1">POST /api/folders <a class="header-anchor" href="#post-api-folders" aria-label="Permalink to &quot;POST /api/folders&quot;">​</a></h3><p>Create a new folder.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>name</td><td>string</td><td>Yes</td><td>Folder name</td></tr></tbody></table><p><strong>Response:</strong> Folder object</p><h3 id="get-api-folders-id" tabindex="-1">GET /api/folders/:id <a class="header-anchor" href="#get-api-folders-id" aria-label="Permalink to &quot;GET /api/folders/:id&quot;">​</a></h3><p>Get a folder by ID.</p><p><strong>Response:</strong> Folder object</p><h3 id="patch-api-folders-id" tabindex="-1">PATCH /api/folders/:id <a class="header-anchor" href="#patch-api-folders-id" aria-label="Permalink to &quot;PATCH /api/folders/:id&quot;">​</a></h3><p>Rename a folder.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>name</td><td>string</td><td>Yes</td><td>New folder name</td></tr></tbody></table><p><strong>Response:</strong> Updated folder object</p><h3 id="delete-api-folders-id" tabindex="-1">DELETE /api/folders/:id <a class="header-anchor" href="#delete-api-folders-id" aria-label="Permalink to &quot;DELETE /api/folders/:id&quot;">​</a></h3><p>Delete a folder and remove all document associations.</p><p><strong>Response:</strong> <code>204 No Content</code></p><h3 id="get-api-folders-id-sifts" tabindex="-1">GET /api/folders/:id/sifts <a class="header-anchor" href="#get-api-folders-id-sifts" aria-label="Permalink to &quot;GET /api/folders/:id/sifts&quot;">​</a></h3><p>List all sifts linked to a folder.</p><p><strong>Response:</strong> Array of sift objects</p><h3 id="post-api-folders-id-sifts" tabindex="-1">POST /api/folders/:id/sifts <a class="header-anchor" href="#post-api-folders-id-sifts" aria-label="Permalink to &quot;POST /api/folders/:id/sifts&quot;">​</a></h3><p>Link a sift to a folder. All existing folder documents will be queued for processing by the sift.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>sift_id</td><td>string</td><td>Yes</td><td>ID of the sift to link</td></tr></tbody></table><p><strong>Response:</strong> <code>201 Created</code></p><h3 id="delete-api-folders-id-sifts-sift-id" tabindex="-1">DELETE /api/folders/:id/sifts/:sift_id <a class="header-anchor" href="#delete-api-folders-id-sifts-sift-id" aria-label="Permalink to &quot;DELETE /api/folders/:id/sifts/:sift_id&quot;">​</a></h3><p>Unlink a sift from a folder.</p><p><strong>Response:</strong> <code>204 No Content</code></p><h3 id="get-api-folders-id-documents" tabindex="-1">GET /api/folders/:id/documents <a class="header-anchor" href="#get-api-folders-id-documents" aria-label="Permalink to &quot;GET /api/folders/:id/documents&quot;">​</a></h3><p>List all documents in a folder.</p><p><strong>Response:</strong> Array of document objects with per-sift processing status</p><h3 id="post-api-folders-id-documents" tabindex="-1">POST /api/folders/:id/documents <a class="header-anchor" href="#post-api-folders-id-documents" aria-label="Permalink to &quot;POST /api/folders/:id/documents&quot;">​</a></h3><p>Upload one or more documents to a folder. All linked sifts will process each document automatically.</p><p><strong>Request:</strong> <code>multipart/form-data</code> with one or more <code>files</code> fields.</p><p><strong>Response:</strong> Array of created document objects</p><h2 id="documents" tabindex="-1">Documents <a class="header-anchor" href="#documents" aria-label="Permalink to &quot;Documents&quot;">​</a></h2><h3 id="get-api-documents-id" tabindex="-1">GET /api/documents/:id <a class="header-anchor" href="#get-api-documents-id" aria-label="Permalink to &quot;GET /api/documents/:id&quot;">​</a></h3><p>Get a document by ID, including per-sift processing status.</p><p><strong>Response:</strong> Document object</p><h3 id="delete-api-documents-id" tabindex="-1">DELETE /api/documents/:id <a class="header-anchor" href="#delete-api-documents-id" aria-label="Permalink to &quot;DELETE /api/documents/:id&quot;">​</a></h3><p>Delete a document and all associated records.</p><p><strong>Response:</strong> <code>204 No Content</code></p><h3 id="post-api-documents-id-reprocess" tabindex="-1">POST /api/documents/:id/reprocess <a class="header-anchor" href="#post-api-documents-id-reprocess" aria-label="Permalink to &quot;POST /api/documents/:id/reprocess&quot;">​</a></h3><p>Re-queue a document for processing by all linked sifts (or a specific sift).</p><p><strong>Query parameters:</strong></p><table tabindex="0"><thead><tr><th>Parameter</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>sift_id</td><td>string</td><td>Reprocess for a specific sift only</td></tr></tbody></table><p><strong>Response:</strong> <code>202 Accepted</code></p><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><h3 id="get-api-webhooks" tabindex="-1">GET /api/webhooks <a class="header-anchor" href="#get-api-webhooks" aria-label="Permalink to &quot;GET /api/webhooks&quot;">​</a></h3><p>List all registered webhooks.</p><p><strong>Response:</strong> Array of webhook objects</p><h3 id="post-api-webhooks" tabindex="-1">POST /api/webhooks <a class="header-anchor" href="#post-api-webhooks" aria-label="Permalink to &quot;POST /api/webhooks&quot;">​</a></h3><p>Register a new webhook.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>events</td><td>string or array</td><td>Yes</td><td>Event name(s) or wildcard pattern</td></tr><tr><td>url</td><td>string</td><td>Yes</td><td>HTTPS URL to POST events to</td></tr><tr><td>sift_id</td><td>string</td><td></td><td>Filter to events for a specific sift</td></tr></tbody></table><p><strong>Response:</strong> Webhook object</p><h3 id="delete-api-webhooks-id" tabindex="-1">DELETE /api/webhooks/:id <a class="header-anchor" href="#delete-api-webhooks-id" aria-label="Permalink to &quot;DELETE /api/webhooks/:id&quot;">​</a></h3><p>Delete a registered webhook.</p><p><strong>Response:</strong> <code>204 No Content</code></p><h2 id="aggregations" tabindex="-1">Aggregations <a class="header-anchor" href="#aggregations" aria-label="Permalink to &quot;Aggregations&quot;">​</a></h2><h3 id="get-api-aggregations" tabindex="-1">GET /api/aggregations <a class="header-anchor" href="#get-api-aggregations" aria-label="Permalink to &quot;GET /api/aggregations&quot;">​</a></h3><p>List all aggregations for the authenticated user.</p><p><strong>Response:</strong> Array of aggregation objects</p><h3 id="post-api-aggregations" tabindex="-1">POST /api/aggregations <a class="header-anchor" href="#post-api-aggregations" aria-label="Permalink to &quot;POST /api/aggregations&quot;">​</a></h3><p>Create a new named aggregation from a natural language query.</p><p><strong>Request body:</strong></p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td>sift_id</td><td>string</td><td>Yes</td><td>ID of the sift to query</td></tr><tr><td>name</td><td>string</td><td>Yes</td><td>Human-readable name</td></tr><tr><td>query</td><td>string</td><td>Yes</td><td>Natural language query</td></tr></tbody></table><p><strong>Response:</strong> Aggregation object</p><h3 id="get-api-aggregations-id" tabindex="-1">GET /api/aggregations/:id <a class="header-anchor" href="#get-api-aggregations-id" aria-label="Permalink to &quot;GET /api/aggregations/:id&quot;">​</a></h3><p>Get an aggregation by ID.</p><p><strong>Response:</strong> Aggregation object</p><h3 id="get-api-aggregations-id-result" tabindex="-1">GET /api/aggregations/:id/result <a class="header-anchor" href="#get-api-aggregations-id-result" aria-label="Permalink to &quot;GET /api/aggregations/:id/result&quot;">​</a></h3><p>Run the aggregation pipeline and return results.</p><p><strong>Response:</strong> Array of result documents</p><h3 id="post-api-aggregations-id-regenerate" tabindex="-1">POST /api/aggregations/:id/regenerate <a class="header-anchor" href="#post-api-aggregations-id-regenerate" aria-label="Permalink to &quot;POST /api/aggregations/:id/regenerate&quot;">​</a></h3><p>Regenerate the aggregation pipeline from its natural language query (useful when the sift schema changes).</p><p><strong>Response:</strong> Updated aggregation object</p><h3 id="delete-api-aggregations-id" tabindex="-1">DELETE /api/aggregations/:id <a class="header-anchor" href="#delete-api-aggregations-id" aria-label="Permalink to &quot;DELETE /api/aggregations/:id&quot;">​</a></h3><p>Delete an aggregation.</p><p><strong>Response:</strong> <code>204 No Content</code></p>',149)])])}const u=e(o,[["render",i]]);export{c as __pageData,u as default};
